// Version minimaliste de html2canvas pour Carbonely
// Capture basique d'éléments HTML

(function(){
    window.html2canvas = function(element, options) {
        return new Promise((resolve, reject) => {
            try {
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');
                
                // Dimensions
                const rect = element.getBoundingClientRect();
                canvas.width = rect.width * (options?.scale || 2);
                canvas.height = rect.height * (options?.scale || 2);
                
                // Style de fond
                ctx.fillStyle = options?.backgroundColor || '#ffffff';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                
                // Rendu simplifié
                this.renderElement(element, ctx, options);
                
                resolve(canvas);
            } catch (error) {
                reject(error);
            }
        });
    };
    
    html2canvas.renderElement = function(element, ctx, options) {
        // Style calculé
        const style = window.getComputedStyle(element);
        
        // Couleur de fond
        if (style.backgroundColor !== 'rgba(0, 0, 0, 0)') {
            ctx.fillStyle = style.backgroundColor;
            ctx.fillRect(0, 0, ctx.canvas.width, ctx.canvas.height);
        }
        
        // Rendu du texte
        if (element.textContent && element.tagName !== 'SCRIPT' && element.tagName !== 'STYLE') {
            ctx.font = `${style.fontWeight} ${style.fontSize} ${style.fontFamily}`;
            ctx.fillStyle = style.color;
            ctx.textAlign = 'left';
            ctx.textBaseline = 'top';
            
            const lines = element.textContent.split('\n');
            const lineHeight = parseInt(style.fontSize) * 1.2;
            
            lines.forEach((line, i) => {
                if (line.trim()) {
                    ctx.fillText(line.trim(), 10, 10 + i * lineHeight);
                }
            });
        }
        
        // Rendu des enfants
        Array.from(element.children).forEach(child => {
            this.renderElement(child, ctx, options);
        });
    };
    
    // Pour les cas d'utilisation comme: html2canvas(element).then(...)
    window.html2canvas = html2canvas;
})();